// OAuth Configuration
const clientId = 'your_client_id';
const redirectUri = encodeURIComponent('http://localhost:3000/callback');
const authorizationEndpoint = 'https://oauth.example.com/authorize';

// Function to initiate the OAuth flow
function login() {
    const state = generateRandomString(16);
    localStorage.setItem('oauthState', state);

    const authUrl = `${authorizationEndpoint}?response_type=code&client_id=${clientId}&redirect_uri=${redirectUri}&scope=read+write&state=${state}`;
    window.location.href = authUrl;
}

// Function to handle the callback
async function handleCallback() {
    const urlParams = new URLSearchParams(window.location.search);
    const code = urlParams.get('code');
    const state = urlParams.get('state');

    if (state !== localStorage.getItem('oauthState')) {
        throw new Error('CSRF token mismatch');
    }

    localStorage.removeItem('oauthState');

    try {
        const response = await fetch('https://oauth.example.com/token', {
            method: 'POST',
            headers: {
                'Content-Type': 'application/x-www-form-urlencoded'
            },
            body: `grant_type=authorization_code&code=${code}&redirect_uri=${redirectUri}&client_id=${clientId}`
        });

        const data = await response.json();
        localStorage.setItem('access_token', data.access_token);
        localStorage.setItem('refresh_token', data.refresh_token);

        // Redirect to home page or desired route
        window.location.href = '/home';
    } catch (error) {
        console.error('Error during token exchange:', error);
    }
}

// Function to generate a random string for CSRF protection
function generateRandomString(length) {
    let result = '';
    const characters = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789';
    for (let i = 0; i < length; i++) {
        result += characters.charAt(Math.floor(Math.random() * characters.length));
    }
    return result;
}

// Function to fetch protected resource using access token
async function fetchProtectedResource() {
    const accessToken = localStorage.getItem('access_token');
    if (!accessToken) {
        throw new Error('Access token not found');
    }

    try {
        const response = await fetch('https://api.example.com/protected', {
            headers: {
                'Authorization': `Bearer ${accessToken}`
            }
        });

        return await response.json();
    } catch (error) {
        console.error('Error fetching protected resource:', error);
        throw error;
    }
}

// Example usage
window.addEventListener('load', () => {
    const params = new URLSearchParams(window.location.search);
    if (params.has('code')) {
        handleCallback();
    }
});

document.getElementById('login-button').addEventListener('click', login);

async function displayProtectedData() {
    try {
        const data = await fetchProtectedResource();
        console.log(data);
    } catch (error) {
        console.error('Failed to fetch protected data:', error);
    }
}

// Call the function to display protected data when needed
displayProtectedData();